// n8n: CODE - Normalize Data (technical + speech assessment)
// Paste into: CODE - Normalize Data (after CFG - Assessment Config)

const item = $input.first().json;
const body = item.body || {};
const query = item.query || {};

const cleanEmail = (raw) => {
  const first = String(raw || '').trim().toLowerCase().split(/\n/)[0].trim();
  return first.split(/\s+regards/i)[0].trim();
};

const session_id = String(
  body.sessionId || body.session_id || query.sessionId || query.session_id || ''
).trim();
const candidate_email = cleanEmail(
  body.email || body.candidate_email || query.email || query.candidate_email
);
const answer = String(body.answer || query.answer || '').trim();
const current_phase = parseInt(body.phase || body.current_phase || query.phase || '1', 10);
const tab_switches = parseInt(body.tabSwitches ?? body.tab_switches ?? '0', 10);
const assessment_mode = String(
  body.assessment_mode || body.mode || query.assessment_mode || 'text'
).trim().toLowerCase();

const speech_metrics =
  body.speech_metrics && typeof body.speech_metrics === 'object'
    ? body.speech_metrics
    : {};
const audio_url = String(body.audio_url || body.audioUrl || '').trim();

const nested = item.config || {};
const config = {
  supabase_url: nested.supabase_url || item.supabase_url || '',
  supabase_key: nested.supabase_key || item.supabase_key || '',
  gemini_model: nested.gemini_model || nested.groq_model || item.gemini_model || item.groq_model || '',
  groq_model: nested.groq_model || item.groq_model || '',
  max_questions: Number(nested.max_questions ?? item.max_questions ?? 5),
  speech_phases: Number(nested.speech_phases ?? item.speech_phases ?? 3),
  speech_enabled:
    nested.speech_enabled === true ||
    nested.speech_enabled === 'true' ||
    item.speech_enabled === true ||
    item.speech_enabled === 'true' ||
    Number(nested.speech_phases ?? item.speech_phases ?? 3) > 0,
  technical_weight: Number(nested.technical_weight ?? item.technical_weight ?? 0.7),
  speech_weight: Number(nested.speech_weight ?? item.speech_weight ?? 0.3),
  interviewer_email: nested.interviewer_email || item.interviewer_email || '',
  organization_name: nested.organization_name || item.organization_name || '',
  requisition_title: nested.requisition_title || '',
  requisition_requirements: nested.requisition_requirements || '',
  fail_score_threshold: Number(nested.fail_score_threshold ?? item.fail_score_threshold ?? 30),
  pass_score_threshold: Number(nested.pass_score_threshold ?? item.pass_score_threshold ?? 60),
  timer_min_seconds: Number(nested.timer_min_seconds ?? item.timer_min_seconds ?? 60),
  timer_max_seconds: Number(nested.timer_max_seconds ?? item.timer_max_seconds ?? 600),
  table_assessment_sessions: nested.table_assessment_sessions || 'assessment_sessions',
};

return [
  {
    json: {
      session_id,
      candidate_email,
      answer,
      current_phase,
      tab_switches,
      assessment_mode,
      speech_metrics,
      audio_url,
      config,
    },
  },
];

// n8n: CODE - Build LLM context (assessment phases 1–5)
// Paste into: CODE - Build LLM context (before Basic LLM Chain)

const norm = $('CODE - Normalize Data').first().json;
const raw = $input.first().json;
const session = Array.isArray(raw) ? raw[0] : raw;
if (!session?.id) {
  throw new Error('No assessment session row for id=' + norm.session_id);
}

let history = session.interview_history;
if (typeof history === 'string') {
  try {
    history = JSON.parse(history);
  } catch (e) {
    history = [];
  }
}
if (!Array.isArray(history)) history = [];

let sessionConfig = session.config;
if (typeof sessionConfig === 'string') {
  try {
    sessionConfig = JSON.parse(sessionConfig);
  } catch (e) {
    sessionConfig = {};
  }
}
if (!sessionConfig || typeof sessionConfig !== 'object') sessionConfig = {};

const cfg = {
  ...norm.config,
  ...sessionConfig,
  requisition_title:
    sessionConfig.requisition_title || norm.config?.requisition_title || '',
  requisition_requirements:
    sessionConfig.requisition_requirements || norm.config?.requisition_requirements || '',
  groq_model:
    sessionConfig.groq_model || norm.config?.groq_model || 'llama-3.3-70b-versatile',
  max_questions: Number(sessionConfig.max_questions || norm.config?.max_questions || 5),
  fail_score_threshold: Number(
    sessionConfig.fail_score_threshold ?? norm.config?.fail_score_threshold ?? 30
  ),
  pass_score_threshold: Number(
    sessionConfig.pass_score_threshold ?? norm.config?.pass_score_threshold ?? 60
  ),
  timer_min_seconds: Number(sessionConfig.timer_min_seconds ?? norm.config?.timer_min_seconds ?? 60),
  timer_max_seconds: Number(sessionConfig.timer_max_seconds ?? norm.config?.timer_max_seconds ?? 600),
};

const ph = Number(norm.current_phase || 1);
const maxQ = Number(cfg.max_questions || 5);
const isFinal = ph >= maxQ;
const failThreshold = Number(cfg.fail_score_threshold ?? 30);

const jdTitle = String(cfg.requisition_title || '').trim();
const jdReq = String(cfg.requisition_requirements || '').trim();
if (!jdTitle || !jdReq) {
  throw new Error(
    'JD missing on assessment session. Complete CV screening with recruiter form JD first (session.config.requisition_title / requisition_requirements).'
  );
}

function extractJdThemes(text) {
  const lines = String(text)
    .split(/\r?\n|(?<=[.;])\s+/)
    .flatMap((chunk) => chunk.split(/\s*[•\-*]\s+/))
    .map((s) => s.replace(/^[\s\d.)(]+/, '').trim())
    .filter((s) => s.length >= 12);
  return lines.length ? [...new Set(lines)].slice(0, 10) : [String(text).slice(0, 500)];
}

const jdThemes = extractJdThemes(jdReq);
const phaseFocusLanes = [
  'JD core responsibilities and must-have skills for this role (breadth, not deep-dive on one tool)',
  'JD system design / architecture / integration — how systems connect and scale for this role',
  'JD hands-on implementation, APIs, data, delivery, or feature ownership',
  'JD quality bar: security, performance, reliability, testing, monitoring, or DevOps',
  'Holistic JD role fit — can this candidate perform the full job',
];

const cvText = String(session.cv_plaintext || '').slice(0, 8000);
const historyText = history
  .map(
    (h) =>
      `Phase ${h.phase} Q: ${h.question_text || h.question || ''} | A: ${h.answer_text ?? 'pending'} | Score: ${h.score ?? 'N/A'}`
  )
  .join('\n');

const themesAsked = history
  .filter((h) => h.question_text || h.question)
  .map((h) => `Phase ${h.phase}: ${String(h.question_text || h.question).slice(0, 140)}`)
  .join('\n');

const cvTopicsUsed = history
  .filter((h) => h.question_text || h.question)
  .map((h) => String(h.question_text || h.question).slice(0, 100))
  .join('\n');

function extractCvAnchors(text) {
  const cv = String(text || '');
  const projects =
    cv.match(/(?:project|built|developed|engineered|implemented|led)[^.]{10,120}/gi) || [];
  const skills =
    cv.match(
      /\b(React|Angular|Vue|Node\.?js|Python|Django|Flask|SQL|PostgreSQL|MySQL|MongoDB|\.NET|ASP\.NET|C#|Java|Spring|AWS|Azure|GCP|Docker|Kubernetes|Redis|Kafka|REST|GraphQL|TypeScript|JavaScript|EF\s*Core|LINQ|JWT|OAuth|microservices?|APIM|CI\/CD|GitHub Actions)\b/gi
    ) || [];
  const employers = cv.match(/(?:at|@)\s+[A-Z][A-Za-z0-9&.\s]{2,40}(?:,|\.|\s{2})/g) || [];
  const anchors = [
    ...new Set([
      ...projects.slice(0, 5).map((p) => p.trim().slice(0, 100)),
      ...skills.slice(0, 8),
      ...employers.slice(0, 3).map((e) => e.trim()),
    ]),
  ].filter(Boolean);
  return anchors.length ? anchors : ['(parse named projects, tools, employers from CV excerpt)'];
}

const cvAnchors = extractCvAnchors(cvText);

const currentQuestionRow = history.find((h) => Number(h.phase) === ph);
const currentQuestionText = String(
  currentQuestionRow?.question_text || currentQuestionRow?.question || ''
).trim();

const prevPhaseRow = history.find((h) => Number(h.phase) === ph - 1);
const prevTimeLimit = prevPhaseRow?.time_limit_seconds ?? null;

const nextPhaseNum = ph + 1;
const nextFocusLane = !isFinal
  ? phaseFocusLanes[Math.min(nextPhaseNum - 1, phaseFocusLanes.length - 1)]
  : '';
const nextJdTheme = !isFinal
  ? jdThemes[(nextPhaseNum - 1) % jdThemes.length] || nextFocusLane
  : '';
const nextCvAnchor = !isFinal
  ? cvAnchors[(nextPhaseNum - 1) % cvAnchors.length] || cvAnchors[0]
  : '';

const sharedRules = `"""You are an elite technical interviewer running a structured ${maxQ}-phase screening for ${cfg.organization_name || 'the company'}.

PRIMARY GOAL: Each phase tests a DIFFERENT combination of JD requirement + CV evidence. Never from CV alone. Never from JD alone.

═══════════════════════════════════════ CV + JD DUAL-SOURCE (MOST IMPORTANT) ═══════════════════════════════════════
Every question MUST explicitly combine BOTH sources in one cohesive prompt:
  (A) A specific JD requirement, responsibility, or outcome from the Job Description, AND
  (B) A specific CV anchor — named project, employer, tool, or experience from the candidate's CV.

Question formula (use every time):
  "The role requires [JD requirement]. Your CV shows [CV project/skill/employer] — how did/would you [technical task linking both]?"

Rules:
  - Each phase = NEW JD theme + NEW CV anchor (rotate both — do not reuse).
  - Spread coverage across the full JD AND across different parts of the CV.
  - NEVER ask a question answerable without reading BOTH the JD and this CV.
  - NEVER deep-dive the same CV project or same JD bullet in more than one phase.

Phase topic lanes (pair with a fresh JD theme + CV anchor each phase):
  Phase 1: ${phaseFocusLanes[0]}
  Phase 2: ${phaseFocusLanes[1]}
  Phase 3: ${phaseFocusLanes[2]}
  Phase 4: ${phaseFocusLanes[3]}
  Phase 5: ${phaseFocusLanes[4]}

JD themes (rotate — one per phase):
${jdThemes.map((t, i) => `  ${i + 1}. ${t}`).join('\n')}

CV anchors detected (rotate — pick a different one each phase):
${cvAnchors.map((a, i) => `  ${i + 1}. ${a}`).join('\n')}

When writing next_question:
  1. Pick JD theme for phase N NOT used in "Themes already asked".
  2. Pick CV anchor NOT used in "CV anchors already used".
  3. Write ONE question that names BOTH in the same sentence.
  4. If CV lacks a skill the JD requires, pair the JD theme with the closest related CV experience and ask how they would bridge the gap.

FORBIDDEN:
  - CV-only questions (no JD requirement named).
  - JD-only questions (no CV project/skill/employer named).
  - Repeating the same CV project or same JD theme across phases.
  - Generic textbook questions any candidate could answer.

═══════════════════════════════════════ SCORING — ANSWER MUST MATCH THE QUESTION ASKED ═══════════════════════════════════════
Score ONLY how well the candidate answered THE SPECIFIC question for this phase (see "Question asked this phase" below).

Weighting:
  - 50% RELEVANCE: Did they answer what was asked (both JD and CV parts of the question)?
  - 25% JD FIT: Does the answer show they can meet the role requirement?
  - 25% CV EVIDENCE: Concrete examples from their stated experience (not invented).

Off-topic / mismatch penalties (apply FIRST):
  - Answer is about a different topic than the question → score ≤ 15
  - Buzzwords only, no link to the question → score ≤ 25
  - Partially on-topic but vague → 30–50
  - Directly answers the question with technical detail → 55–75
  - Strong, specific, JD-aligned answer with evidence → 76–100

Do NOT give high scores for impressive but irrelevant content.

═══════════════════════════════════════ STRUCTURE ═══════════════════════════════════════
- Exactly ${maxQ} phases. Phases 1–4: score + one next_question. Phase ${maxQ}: score + PASS/FAIL, next_question "".
- Phase 1 question already exists in history — grade it; write phase 2 when current phase is 1.
- Empty/timeout/[SYSTEM TERMINATION] → score 0–15, next_question "" if integrity.

═══════════════════════════════════════ TIME LIMIT (phases 1–4) ═══════════════════════════════════════
Set time_limit_seconds (60–600) and complexity_tier A|B|C|D from next_question depth.

═══════════════════════════════════════ OUTPUT — JSON ONLY ═══════════════════════════════════════
Phases 1–4: {"score":number,"feedback":string,"suggested_answer":string,"next_question":string,"time_limit_seconds":number,"complexity_tier":"A"|"B"|"C"|"D"}
Phase ${maxQ}: {"status":"finished","result":"PASS"|"FAIL","score":number,"feedback":string,"suggested_answer":string,"next_question":""}

Job title: ${jdTitle}
JD requirements:
${jdReq}

Candidate CV (excerpt):
${cvText}

Prior Q&A:
${historyText || '(none yet)'}

Themes already asked (next question MUST use a DIFFERENT JD topic):
${themesAsked || '(none yet)'}

CV anchors already used (do NOT reuse same project/stack):
${cvTopicsUsed || '(none yet)'}

Tab switches: ${norm.tab_switches || 0}`;

let systemContent;
if (isFinal) {
  systemContent = `${sharedRules}

Current phase: ${ph} of ${maxQ} (FINAL).
Question asked this phase:
${currentQuestionText || '(see prior Q&A)'}

Answer to grade:
${norm.answer}

Tasks:
1. Score 0–100 based on relevance to the question above + JD holistic fit.
2. result = PASS only if candidate demonstrated breadth across JD topics in the session; else FAIL.
3. feedback + suggested_answer (max 2 short paragraphs).

Output: {"status":"finished","result":"PASS"|"FAIL","score":number,"feedback":string,"suggested_answer":string,"next_question":""}`;
} else {
  systemContent = `${sharedRules}

Current phase: ${ph} of ${maxQ}.
Question asked this phase (score against THIS):
${currentQuestionText || '(see prior Q&A)'}

Answer to grade:
${norm.answer}
${prevTimeLimit != null ? `Previous phase time_limit_seconds: ${prevTimeLimit}` : ''}

Next question target — phase ${nextPhaseNum}:
  Focus lane: ${nextFocusLane}
  JD theme to use: ${nextJdTheme}
  CV anchor to use: ${nextCvAnchor}

Tasks:
1. Score current answer 0–100 (must address BOTH JD and CV parts of the question asked).
2. feedback — note if answer ignored JD requirement or lacked CV-specific evidence.
3. suggested_answer (max 2 short paragraphs).
4. next_question for phase ${nextPhaseNum} — MUST name one JD requirement AND one CV anchor; new topic pair, no repeats.
5. time_limit_seconds + complexity_tier.

Output: {"score":number,"feedback":string,"suggested_answer":string,"next_question":string,"time_limit_seconds":number,"complexity_tier":"A"|"B"|"C"|"D"}`;
}

const body = {
  model: cfg.groq_model || 'llama-3.3-70b-versatile',
  messages: [
    { role: 'system', content: systemContent },
    { role: 'user', content: 'Evaluate and respond with JSON only.' },
  ],
  temperature: isFinal ? 0.1 : 0.35,
  response_format: { type: 'json_object' },
};

return [
  {
    json: {
      groq_assessment_request: body,
      prompt: systemContent,
      session,
      norm: { ...norm, config: cfg },
      isFinal,
      failThreshold,
      current_question_text: currentQuestionText,
      next_jd_theme: nextJdTheme,
      next_cv_anchor: nextCvAnchor,
      next_focus_lane: nextFocusLane,
    },
  },
];

// n8n: CODE - Parse Technical Result (phases 1–5, speech handoff)
// Paste into: CODE - Parse Technical Result (after Basic LLM Chain — technical branch)

function timerBounds(config) {
  const min = Number(config?.timer_min_seconds);
  const max = Number(config?.timer_max_seconds);
  return {
    min: Number.isFinite(min) && min > 0 ? min : 60,
    max: Number.isFinite(max) && max > 0 ? max : 600,
  };
}

function clampSeconds(sec, config) {
  const { min, max } = timerBounds(config);
  return Math.min(max, Math.max(min, Math.round(sec)));
}

// Seconds band per complexity tier
function tierTimeRange(tier) {
  switch (String(tier || '').toUpperCase()) {
    case 'A':
      return [60, 120];
    case 'B':
      return [150, 240];
    case 'C':
      return [270, 390];
    case 'D':
      return [420, 600];
    default:
      return null;
  }
}

// Infer a tier when the model omits or returns a junk tier
function inferTierFromQuestion(questionText) {
  const q = String(questionText || '');
  const words = q.trim().split(/\s+/).filter(Boolean).length;
  const subParts =
    (q.match(/\?/g) || []).length +
    (q.match(/\b(and|also|furthermore|additionally|then|as well as)\b/gi) || []).length;
  const heavy =
    /\b(architecture|design|schema|scalable|scalability|concurrency|distributed|trade-?off|optimi[sz]e|throughput|migration|pipeline|multi-?tenant|security|performance|caching|indexing)\b/i.test(
      q
    );

  if (words <= 28 && subParts <= 1 && !heavy) return 'A';
  if (words >= 80 || (heavy && subParts >= 3)) return 'D';
  if (words >= 50 || heavy) return 'C';
  return 'B';
}

// Deterministic per-question time: tier sets the band, question length positions
// within it, the model's value (if sane) is blended in. Different questions →
// different times, longer/harder questions → more seconds.
function deriveTimeLimitSeconds(rawLlmTime, tier, questionText, config, phase) {
  const usableTier =
    tierTimeRange(tier) ? tier : inferTierFromQuestion(questionText);
  const [lo, hi] = tierTimeRange(usableTier) || [150, 240];

  const words = String(questionText || '').trim().split(/\s+/).filter(Boolean).length;
  const span = Math.max(1, 90 - 20);
  const t = Math.max(0, Math.min(1, (words - 20) / span));
  let computed = lo + t * (hi - lo);

  const llm = Number(rawLlmTime);
  if (Number.isFinite(llm) && llm >= lo && llm <= hi) {
    computed = (llm + computed) / 2;
  }

  let sec = Math.round(computed / 15) * 15;
  sec = Math.max(lo, Math.min(hi, sec));
  return { seconds: clampSeconds(sec, config), tier: usableTier };
}

function buildDeadline(isoStart, seconds) {
  const start = isoStart ? new Date(isoStart) : new Date();
  return new Date(start.getTime() + seconds * 1000).toISOString();
}

function extractLlmText(api) {
  if (!api || typeof api !== 'object') return '';
  if (typeof api.text === 'string' && api.text.trim()) return api.text.trim();
  if (typeof api.output === 'string' && api.output.trim()) return api.output.trim();
  if (typeof api.response === 'string' && api.response.trim()) return api.response.trim();
  const c0 = api.choices?.[0];
  if (c0?.message?.content) return String(c0.message.content).trim();
  if (typeof c0?.text === 'string') return c0.text.trim();
  const parts = api.candidates?.[0]?.content?.parts;
  if (Array.isArray(parts) && parts[0]?.text) return String(parts[0].text).trim();
  return '';
}

function salvageNextQuestionFromText(rawText) {
  const text = String(rawText || '');
  if (!text.trim()) return '';

  const patterns = [
    /"next_question"\s*:\s*"((?:\\.|[^"\\])*)"/i,
    /"nextQuestion"\s*:\s*"((?:\\.|[^"\\])*)"/i,
    /next_question\s*[:=]\s*"((?:\\.|[^"\\])*)"/i,
  ];
  for (const re of patterns) {
    const m = text.match(re);
    if (m?.[1]) {
      return m[1].replace(/\\n/g, '\n').replace(/\\"/g, '"').replace(/\\\\/g, '\\').trim();
    }
  }
  return '';
}

function parseLlmContent(api) {
  if (
    api &&
    (api.score != null ||
      api.feedback ||
      api.next_question ||
      api.nextQuestion ||
      api.result ||
      api.status === 'finished')
  ) {
    const nextQ = String(api.next_question || api.nextQuestion || api.question || '').trim();
    if (!nextQ) {
      const salvaged = salvageNextQuestionFromText(extractLlmText(api));
      if (salvaged) {
        return { ...api, next_question: salvaged, nextQuestion: salvaged };
      }
    }
    return api;
  }
  const rawText = extractLlmText(api);
  if (!rawText) {
    return {
      status: 'in_progress',
      score: 0,
      feedback: 'Empty model output.',
      next_question: '',
      nextQuestion: '',
    };
  }
  try {
    const cleaned = rawText.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
    const parsed = JSON.parse(cleaned);
    const nextQ = String(parsed.next_question || parsed.nextQuestion || parsed.question || '').trim();
    if (!nextQ) {
      const salvaged = salvageNextQuestionFromText(rawText);
      if (salvaged) {
        parsed.next_question = salvaged;
        parsed.nextQuestion = salvaged;
      }
    }
    return parsed;
  } catch (e) {
    const salvaged = salvageNextQuestionFromText(rawText);
    return {
      status: 'in_progress',
      score: 0,
      feedback: salvaged ? 'Recovered question from partial model output.' : 'Could not parse model output.',
      next_question: salvaged,
      nextQuestion: salvaged,
    };
  }
}

function extractJdThemes(text) {
  const lines = String(text)
    .split(/\r?\n|(?<=[.;])\s+/)
    .flatMap((chunk) => chunk.split(/\s*[•\-*]\s+/))
    .map((s) => s.replace(/^[\s\d.)(]+/, '').trim())
    .filter((s) => s.length >= 12);
  return lines.length ? [...new Set(lines)].slice(0, 10) : [String(text).slice(0, 400)];
}

function extractCvAnchors(text) {
  const cv = String(text || '');
  const projects =
    cv.match(/(?:project|built|developed|engineered|implemented|led)[^.]{10,120}/gi) || [];
  const skills =
    cv.match(
      /\b(React|Angular|Vue|Node\.?js|Python|Django|Flask|SQL|PostgreSQL|MySQL|MongoDB|\.NET|ASP\.NET|C#|Java|Spring|AWS|Azure|GCP|Docker|Kubernetes|Redis|Kafka|REST|GraphQL|TypeScript|JavaScript|EF\s*Core|LINQ|JWT|OAuth|microservices?|APIM|CI\/CD|GitHub Actions)\b/gi
    ) || [];
  return [
    ...new Set([
      ...projects.slice(0, 5).map((p) => p.trim().slice(0, 80)),
      ...skills.slice(0, 6),
    ]),
  ].filter(Boolean);
}

function buildFirstSpeechQuestion(cfg, session, speechIndex) {
  const role = String(cfg.requisition_title || 'this role').trim();
  const org = String(cfg.organization_name || 'the company').trim();
  const cvSnippet = String(session.cv_plaintext || '').slice(0, 400).trim();
  const lanes = [
    `Tell me about a time you had to explain a complex technical topic to a non-technical stakeholder at ${org}. How did you ensure they understood, and what was the outcome?`,
    `Describe a situation where you faced pressure, a tight deadline, or conflict at work. How did you communicate with your team and stay composed?`,
    `Why are you interested in the ${role} role, and based on your background, what would you focus on in your first 90 days?`,
  ];
  const idx = Math.max(0, Math.min(lanes.length - 1, Number(speechIndex || 1) - 1));
  let q = lanes[idx];
  if (cvSnippet.length > 40) {
    q += ` (Your CV mentions relevant experience — use a concrete example if possible.)`;
  }
  return q;
}

function buildFallbackNextQuestion(ph, history, cfg, session) {
  const role = String(cfg.requisition_title || 'this role').trim();
  const jdReq = String(cfg.requisition_requirements || '').trim();
  const cv = String(session.cv_plaintext || '');
  const nextPhase = ph + 1;
  const jdThemes = extractJdThemes(jdReq);
  const jdTheme = jdThemes[(nextPhase - 1) % jdThemes.length] || jdReq.slice(0, 200);
  const cvAnchors = extractCvAnchors(cv);
  const cvAnchor = cvAnchors[(nextPhase - 1) % cvAnchors.length] || 'your listed project experience';

  const lanes = [
    `This role requires: "${jdTheme}". Your CV mentions ${cvAnchor} — describe how you applied this to deliver that JD outcome. What did you build and what was the measurable result?`,
    `JD expectation: "${jdTheme}". Drawing on ${cvAnchor} from your CV, explain the architecture and integration choices you would make for this ${role} role.`,
    `For "${jdTheme}" (${role}): Using your experience with ${cvAnchor}, walk through implementation steps, tools, and how you would validate it in production.`,
    `JD quality bar — "${jdTheme}": With ${cvAnchor} on your CV, what security, performance, or reliability risks would you address and how?`,
    `Final phase (${role}): JD requires "${jdTheme}" and your CV shows ${cvAnchor}. Synthesise how your experience maps to this role and what you would deliver in the first 90 days.`,
  ];

  return lanes[Math.min(nextPhase - 1, lanes.length - 1)] || lanes[4];
}

function isIntegrityTermination(answerText) {
  return /^\[system\s+termination/i.test(String(answerText || '').trim());
}

function isScorablePhaseRow(row) {
  if (!row || row.answer_text == null || row.score == null) return false;
  if (row.integrity_terminated || isIntegrityTermination(row.answer_text)) return false;
  const n = Number(row.score);
  return Number.isFinite(n);
}

function buildPhaseSummary(rows) {
  return rows
    .filter((row) => row.answer_text != null)
    .map((row) => {
      if (row.integrity_terminated || isIntegrityTermination(row.answer_text)) {
        return `P${row.phase}:integrity-fail`;
      }
      if (row.score != null) return `P${row.phase}:${row.score}`;
      return null;
    })
    .filter(Boolean)
    .join(', ');
}

function questionRelevanceCap(answerText, questionText) {
  const question = String(questionText || '').trim();
  if (!question || question.length < 20) return null;

  const tokens = question
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .split(/\s+/)
    .filter((w) => w.length > 4);
  const stop = new Set([
    'would', 'could', 'should', 'their', 'there', 'which', 'about', 'describe',
    'explain', 'candidate', 'please', 'specific', 'technical', 'question',
    'implement', 'approach', 'system', 'using',
  ]);
  const keys = [...new Set(tokens.filter((w) => !stop.has(w)))].slice(0, 18);
  if (keys.length < 3) return null;

  const lower = String(answerText || '').toLowerCase();
  const hits = keys.filter((k) => lower.includes(k)).length;
  const ratio = hits / keys.length;

  if (ratio < 0.06) return 12;
  if (ratio < 0.12) return 22;
  if (ratio < 0.2) return 32;
  return null;
}

/** Clamp LLM scores — off-topic and garbage answers must not get free points */
function normalizePhaseScore(answerText, llmScore, questionText) {
  const answer = String(answerText || '').trim();
  let score = Number(llmScore);
  if (!Number.isFinite(score)) score = 0;

  if (!answer) return 0;
  if (isIntegrityTermination(answer)) return null;
  if (/^\[timeout/i.test(answer)) return 0;

  const relevanceCap = questionRelevanceCap(answer, questionText);
  if (relevanceCap != null) score = Math.min(score, relevanceCap);

  const lower = answer.toLowerCase().replace(/\s+/g, ' ').trim();
  const compact = answer.replace(/\s+/g, '');
  const len = compact.length;

  // Keyboard mash: mmmm, qqqqq, ooooo (same char repeated)
  if (len >= 4) {
    const chars = compact.toLowerCase().split('');
    const freq = {};
    for (const c of chars) freq[c] = (freq[c] || 0) + 1;
    const top = Math.max(...Object.values(freq));
    if (Object.keys(freq).length === 1 || top / chars.length >= 0.8) return 0;
  }

  // Trivial non-answers
  if (/^(ok|okay|yes|no|n\/a|na|idk|dunno|sure|fine|\.+|-+)$/i.test(lower)) {
    return Math.min(score, 3);
  }
  if (/^(ok\s+ok|yes\s+yes|no\s+no)$/i.test(lower)) {
    return Math.min(score, 3);
  }

  const techMarkers =
    /\b(api|sql|database|entity|framework|asp\.net|\.net|core|jwt|controller|service|schema|ef\s*core|linq|rest|dto|validation|fluentvalidation|dependency|injection|tenant|auth|middleware|repository|campaign|promotion|bcrypt|rbac|sso|endpoint|migration|index|query|table|class|interface|async|await)\b/i;

  const wordCount = lower.split(/\s+/).filter(Boolean).length;

  // One-liner generic with no technical terms (e.g. phase 1 "yes, system handles products...")
  if (wordCount <= 25 && !techMarkers.test(answer)) {
    return Math.min(score, 15);
  }

  // Very short, no technical signal
  if (len < 30 && !techMarkers.test(answer)) {
    return Math.min(score, 8);
  }

  // Short answer without technical depth — cap generous LLM scores
  if (len < 120 && !techMarkers.test(answer)) {
    return Math.min(score, 18);
  }

  if (len < 200 && score > 40 && !techMarkers.test(answer)) {
    return Math.min(score, 25);
  }

  return Math.max(0, Math.min(100, Math.round(score)));
}

function pickNodeJson(...names) {
  for (const name of names) {
