          !msgId ? 'missing gmail message id' : null,
        ]
          .filter(Boolean)
          .join('; '),
        _gmail_patch_url: '',
        _gmail_patch_body: {},
      },
    },
  ];
}

const b = String(cfg.supabase_url || '').replace(/\/+$/, '');
const tb = cfg.table_assessment_sessions || 'assessment_sessions';

return [
  {
    json: {
      ...ctx,
      gmail_message_id: msgId,
      gmail_thread_id: threadId,
      _gmail_patch_url: `${b}/rest/v1/${tb}?id=eq.${encodeURIComponent(sessionId)}`,
      _gmail_patch_body: {
        gmail_message_id: msgId,
        gmail_thread_id: threadId,
        updated_at: new Date().toISOString(),
      },
    },
  },
];

// n8n: CODE - Build interviewer confirmed mail (interviewer thread reply)
// After CAL (or scheduling-confirmed webhook)

function pickNodeJson(...names) {
  for (const name of names) {
    if (!name) continue;
    try {
      const raw = $(name).first().json;
      if (raw && typeof raw === 'object') return raw;
    } catch (_) {}
  }
  return null;
}

function pickSessionRow() {
  const names = [
    'CODE - Scheduling confirmed from session',
    'HTTP - SB GET session (confirmed)',
    'HTTP - SB GET session (slots)',
    'HTTP - Fetch Session',
    'HTTP - Fetch Session1',
    'CODE - Parse candidate choice',
    'CODE - Prep scheduling from PASS',
  ];
  for (const name of names) {
    const raw = pickNodeJson(name);
    if (!raw) continue;
    const row = raw?.session_row || (Array.isArray(raw) ? raw[0] : raw);
    if (row?.id) return row;
  }
  return {};
}

const ctx = pickNodeJson('CODE - Scheduling confirmed from session') || {};
const base = { ...ctx, ...($input.first().json || {}) };
const session = pickSessionRow();
const cfg = {
  ...(typeof session.config === 'object' ? session.config : {}),
  ...(base.config || {}),
};

const threadId = String(
  session.interviewer_gmail_thread_id ||
    base.interviewer_gmail_thread_id ||
    ctx.interviewer_gmail_thread_id ||
    ''
).trim();
const msgId = String(
  session.interviewer_gmail_message_id ||
    base.interviewer_gmail_message_id ||
    ctx.interviewer_gmail_message_id ||
    ''
).trim();

if (!threadId) {
  throw new Error(
    'interviewer_gmail_thread_id missing — send interviewer pitch mail first (assessment PASS chain).'
  );
}
if (!msgId) {
  throw new Error(
    'interviewer_gmail_message_id missing — PATCH after MAIL - Interviewer pitch mail.'
  );
}

const role = String(cfg.requisition_title || base.requisition_title || 'the role');
const candidateEmail = String(base.candidate_email || session.candidate_email || '');
const slotLabel = String(
  base.selected_slot_label ||
    base.slot_label ||
    (typeof base.chosen_slot === 'object' ? base.chosen_slot?.label : base.chosen_slot) ||
    base.start_iso ||
    'scheduled time'
);
const org = String(cfg.organization_name || 'Talent Acquisition Team');

const mailBodyHtml = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#f1f5f9;font-family:Segoe UI,Arial,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f1f5f9;padding:24px 16px;">
    <tr><td align="center">
      <table width="100%" style="max-width:560px;background:#fff;border-radius:12px;padding:28px;">
        <tr><td style="color:#334155;font-size:15px;line-height:1.6;">
          <p style="margin:0 0 8px;font-size:12px;letter-spacing:.08em;text-transform:uppercase;color:#64748b;">── Interview Confirmed ──</p>
          <p>Hello,</p>
          <p>Interview scheduled for <strong>${candidateEmail.replace(/</g, '&lt;')}</strong> — <strong>${role.replace(/</g, '&lt;')}</strong>.</p>
          <p><strong>Time:</strong> ${slotLabel.replace(/</g, '&lt;')}</p>
          <p>Calendar invite has been created. Candidate confirmation sent in their thread.</p>
          <p>Best regards,<br>${org.replace(/</g, '&lt;')}</p>
        </td></tr>
      </table>
    </td></tr>
  </table>
</body></html>`;

return [
  {
    json: {
      ...base,
      session_id: session.id || base.session_id || ctx.session_id,
      interviewer_email: base.interviewer_email || cfg.interviewer_email,
      interviewer_gmail_thread_id: threadId,
      interviewer_gmail_message_id: msgId,
      mail_body_html: mailBodyHtml,
      config: cfg,
    },
  },
];

// n8n: CODE - Merge Gmail interviewer mail response
// After MAIL - Interviewer pitch (Send) OR MAIL - Reply interviewer thread
// Saves interviewer_gmail_thread_id + interviewer_gmail_message_id on session

function pickContext() {
  const names = [
    'CODE - Build interviewer mail context',
    'CODE - Build interviewer confirmed mail',
    'CODE - Prep scheduling from PASS',
    'CODE - Parse Result',
    'HTTP - Fetch Session',
  ];
  let merged = {};
  for (const name of names) {
    try {
      merged = { ...merged, ...($input.first().json || {}), ...$(name).first().json };
    } catch (_) {}
  }
  return merged;
}

function resolveGmailPayload(input, ...mailNodeNames) {
  if (input && (input.id || input.messageId || input.threadId || input.thread_id)) {
    return input;
  }
  for (const name of mailNodeNames) {
    if (!name) continue;
    try {
      const raw = $(name).first().json;
      if (raw && (raw.id || raw.messageId || raw.threadId || raw.thread_id)) return raw;
    } catch (_) {}
  }
  return input || {};
}

const gmail = resolveGmailPayload($input.first().json, 'MAIL - Interviewer pitch mail', 'MAIL - Interviewer pitch mail1', 'MAIL - Notify interviewer', 'MAIL - Notify interviewer1');
const ctx = pickContext();
const cfg = ctx.config || {};

const msgId = String(gmail.id || gmail.messageId || '').trim();
const threadId = String(gmail.threadId || gmail.thread_id || ctx.interviewer_gmail_thread_id || '').trim();
const sessionId = String(ctx.session_id || ctx.session_db_id || ctx.id || '').trim();
const mailSubject = String(ctx.mail_subject || ctx.interviewer_mail_subject || '').trim();

const patchReady = Boolean(sessionId && threadId && msgId);
const b = String(cfg.supabase_url || '').replace(/\/+$/, '');
const tb = cfg.table_assessment_sessions || 'assessment_sessions';

return [
  {
    json: {
      ...ctx,
      interviewer_gmail_thread_id: threadId || ctx.interviewer_gmail_thread_id || null,
      interviewer_gmail_message_id: msgId || ctx.interviewer_gmail_message_id || null,
      interviewer_mail_subject: mailSubject || ctx.interviewer_mail_subject || null,
      _interviewer_patch_skipped: !patchReady,
      _interviewer_patch_skip_reason: !patchReady
        ? [
            !sessionId ? 'missing session_id' : null,
            !threadId ? 'missing gmail threadId' : null,
            !msgId ? 'missing gmail message id' : null,
          ]
            .filter(Boolean)
            .join('; ')
        : '',
      _interviewer_patch_url: patchReady
        ? `${b}/rest/v1/${tb}?id=eq.${encodeURIComponent(sessionId)}`
        : '',
      _interviewer_patch_body: patchReady
        ? {
            interviewer_gmail_thread_id: threadId,
            interviewer_gmail_message_id: msgId,
            interviewer_mail_subject: mailSubject || undefined,
            updated_at: new Date().toISOString(),
          }
        : {},
    },
  },
];
